class MKAverage {
public:
    MKAverage(int m, int k) : m(m), k(k), sum(0) {
        lo = new multiset<int>();
        mid = new multiset<int>();
        hi = new multiset<int>();
    }

    void addElement(int num) {
        if (dq.size() == m) {
            int front = dq.front();
            dq.pop_front();
            if (lo->count(front)) {
                lo->erase(lo->find(front));
            } else if (mid->count(front)) {
                mid->erase(mid->find(front));
                sum -= front;
            } else {
                hi->erase(hi->find(front));
            }
        }
        dq.push_back(num);
        if (lo->size() == 0 || num <= *lo->rbegin()) {
            lo->insert(num);
        } else if (hi->size() == 0 || num >= *hi->begin()) {
            hi->insert(num);
        } else {
            mid->insert(num);
            sum += num;
        }
        rebalance();
    }

    int calculateMKAverage() {
        if (dq.size() < m) return -1;
        return sum / mid->size();
    }

private:
    int m, k;
    long long sum;
    deque<int> dq;
    multiset<int>* lo;
    multiset<int>* mid;
    multiset<int>* hi;

    void rebalance() {
        while (lo->size() > k) {
            int val = *lo->rbegin();
            lo->erase(lo->find(val));
            mid->insert(val);
            sum += val;
        }
        while (hi->size() > k) {
